      assert 2 * a >= val;
      assert !(2 * a <= s' && b <= s');
      assert !(a <= s' && 2 * b <= s');
      assert !(2 * b <= s' && a <= s');
      assert !(b <= s' && 2 * a <= s');
    }
  }

